func New(
	SettingsFilePath, IconsDirPath string,
) AppDetector {
	return AppDetector{
		settingsFilePath: SettingsFilePath,
		iconsDirPath: IconsDirPath,
		processChangedChan: make(chan *Application),
	}
}

